 private LinearLayout buildDashboard(){LinearLayout page=pageContainer();page.addView(sectionHeader("خانه","خلاصه امروز و روند استفاده"));LinearLayout stats=new LinearLayout(this);stats.setOrientation(LinearLayout.HORIZONTAL);todayTotalValue=statCard(stats,"زمان فعال","0:00",green);idleTodayValue=statCard(stats,"بیکاری/توقف","0:00",red);page.addView(stats);LinearLayout stats2=new LinearLayout(this);stats2.setOrientation(LinearLayout.HORIZONTAL);todayAppsValue=statCard(stats2,"برنامه‌ها","0",blue);idleLimitValue=statCard(stats2,"حد توقف","10 دقیقه",orange);page.addView(stats2);LinearLayout month=cardBox();month.addView(smallMuted("جمع ماه جاری"));monthTotalValue=bigText("0:00",orange);month.addView(monthTotalValue);page.addView(month);timelineView=new MiniTimelineView(this);LinearLayout tl=cardBox();LinearLayout head=new LinearLayout(this);head.setGravity(Gravity.CENTER_VERTICAL);head.addView(titleText("نمای کلی امروز"),new LinearLayout.LayoutParams(0,-2,1));Button out=secondaryButton("−"),in=primaryButton("+");timelineZoomLabel=chip("24h",accent,dark?Color.parseColor("#12342F"):Color.parseColor("#DCFCE7"));out.setTextSize(18);in.setTextSize(18);out.setOnClickListener(v->zoomTimeline(-1));in.setOnClickListener(v->zoomTimeline(1));head.addView(out,new LinearLayout.LayoutParams(dp(46),dp(42)));head.addView(timelineZoomLabel,new LinearLayout.LayoutParams(dp(68),dp(36)));head.addView(in,new LinearLayout.LayoutParams(dp(46),dp(42)));tl.addView(head);tl.addView(timelineView,new LinearLayout.LayoutParams(-1,dp(160)));page.addView(tl);dashboardTopApps=new LinearLayout(this);dashboardTopApps.setOrientation(LinearLayout.VERTICAL);LinearLayout top=cardBox();top.addView(titleText("برنامه‌های پرتکرار امروز"));top.addView(dashboardTopApps);page.addView(top);return page;}
